#!/usr/bin/env python3
"""DGX DEPLOY v19.34.251 — Shadow Tracker measurement-bug fix (the fake 18pt gap / 4,407 would_have_r==0.00).
Root causes fixed: (1) would_have_r hardcoded 0 (track_pending never passed a stop + no stop stored on the decision);
(2) would_have_pnl direction-blind (winning shorts scored as losses); (3) was_executed set from the AI 'proceed'
recommendation (~100%% true) instead of a real fill. Fix: capture direction/stop/target at log time, compute
direction-aware pnl + real R from the stored stop, and link was_executed to a REAL IB fill via mark_executed()
(trade_execution pre-submit hook). Includes a one-time historical backfill script. Idempotent: rewrite, pytest, commit, push, restart."""
import base64, gzip, os, subprocess, sys
FILES = {
    'backend/services/ai_modules/shadow_tracker.py': '',
    'backend/services/ai_modules/trade_consultation.py': '',
    'backend/services/trade_execution.py': '',
    'backend/tests/test_v19_34_251_shadow_tracker_fix.py': '',
    'backend/scripts/backfill_shadow_outcomes_v19_34_251.py': '',
}
REPO=os.getcwd()
def main():
    if not os.path.isdir(os.path.join(REPO,"backend","services")):
        print("[FATAL] not repo root"); sys.exit(1)
    for rel,b in FILES.items():
        dst=os.path.join(REPO,rel); os.makedirs(os.path.dirname(dst),exist_ok=True)
        data=gzip.decompress(base64.b64decode(b)); open(dst,"wb").write(data)
        print(f"[WROTE] {rel} ({len(data)} bytes)")
    print("[TEST] pytest v251 ...")
    r=subprocess.run([sys.executable,"-m","pytest","backend/tests/test_v19_34_251_shadow_tracker_fix.py","backend/tests/test_shadow_tracker_drain.py","-q"],cwd=REPO)
    if r.returncode!=0: print("[FATAL] pytest failed — aborting."); sys.exit(2)
    subprocess.run(["git","add"]+list(FILES.keys()),cwd=REPO)
    c=subprocess.run(["git","commit","-m","v19.34.251 — shadow tracker measurement fix (direction-aware pnl, real would_have_r, real-fill was_executed) + historical backfill"],cwd=REPO)
    if c.returncode!=0: print("[INFO] commit no-op")
    p=subprocess.run(["git","push"],cwd=REPO)
    if p.returncode!=0: print("[WARN] push failed — commit is local")
    print("[RESTART] ./start_backend.sh --force"); subprocess.run(["./start_backend.sh","--force"],cwd=REPO)
    print("[DONE] v19.34.251 deployed. NEW shadow decisions now honest. Run the backfill to repair history:")
    print("       .venv/bin/python backend/scripts/backfill_shadow_outcomes_v19_34_251.py --days 60 --dry-run")
    print("       .venv/bin/python backend/scripts/backfill_shadow_outcomes_v19_34_251.py --days 60 --commit")
if __name__=="__main__": main()
